CREATE TABLE IF NOT EXISTS faqs_faqcategory (id BIGINT AUTO_INCREMENT PRIMARY KEY,module VARCHAR(20) NOT NULL,name VARCHAR(100) NOT NULL,sort_order INT UNSIGNED NOT NULL DEFAULT 0,is_active BOOLEAN NOT NULL DEFAULT TRUE,CONSTRAINT uniq_faq_module_category UNIQUE(module,name)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS faqs_faq (id BIGINT AUTO_INCREMENT PRIMARY KEY,category_id BIGINT NOT NULL,question VARCHAR(255) NOT NULL,answer LONGTEXT NOT NULL,sort_order INT UNSIGNED NOT NULL DEFAULT 0,is_active BOOLEAN NOT NULL DEFAULT TRUE,created_at DATETIME(6) NOT NULL,updated_at DATETIME(6) NOT NULL,FOREIGN KEY(category_id) REFERENCES faqs_faqcategory(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
